INSERT INTO `tb_blog` VALUES (6, 55, 1, '外婆家真香！人均50吃到撑的宝藏杭帮菜', '/imgs/blogs/blog1.jpg', '外婆家真是我吃过最良心的杭帮菜馆！<br>点了6个菜才花了280块，人均不到50块。<br>推荐茶香鸡，外酥里嫩；糖醋里脊酸甜可口；蒜蓉粉丝虾虾肉Q弹！<br>唯一缺点就是人太多，建议提前线上取号。<br>地址：运河上街F4<br>人均：50元<br>推荐指数：4.5星', 12, 0, '2022-01-15 18:00:00', NOW());
INSERT INTO `tb_blog` VALUES (7, 20, 2, '月卡健身一个月，掉了5斤！Keep实测分享', '/imgs/blogs/blog1.jpg', '在Keep健身办了月卡，坚持一个月效果明显！<br>说说感受：器械齐全、教练专业、团课丰富。<br>每天早上跑步机30分钟+力量训练1小时。<br>一个月下来体脂掉了2%，腰围小了2cm。<br>月卡199元性价比超高，推荐给想健身的上班族！<br>地址：运河上街F4<br>人均：199元/月<br>推荐指数：4.8星', 8, 0, '2022-01-20 10:00:00', NOW());
INSERT INTO `tb_blog` VALUES (23, 5, 1, '凌晨2点还在排队！海底捞服务真的绝', '/imgs/blogs/blog1.jpg', '凌晨2点去海底捞还排队了半小时，可见生意有多好！<br>服务没话说：有美甲、擦鞋、等待区小零食。<br>锅底选了牛油+番茄，食材新鲜，虾滑必点！<br>捞面表演也很精彩，适合带外地朋友来体验。<br>缺点是等位时间太长，建议提前在网上排号。<br>地址：上塘路458号水晶城F6<br>人均：104元<br>推荐指数：4.9星', 25, 3, '2022-02-01 02:30:00', NOW());
INSERT INTO `tb_blog` VALUES (24, 10, 5, '周末KTV首选！音响效果好到爆', '/imgs/blogs/blog1.jpg', '开乐迪KTV音效真的很棒，话筒无杂音，曲库很新！<br>周末和朋友开了个中包，唱了4小时人均才40块。<br>小食套餐也便宜，爆米花+可乐才9.9元。<br>包间干净，隔音效果好，就是周末要等位。<br>地址：运河上街F4<br>人均：40元<br>推荐指数：4.5星', 18, 2, '2022-02-05 16:00:00', NOW());
INSERT INTO `tb_blog` VALUES (25, 15, 2, 'TONI&GUY染发实录！这颜色绝了', '/imgs/blogs/blog1.jpg', '终于对头发下手了！在TONI&GUY做了个雾霾蓝灰。<br>理发师TONY很专业，先做了头皮护理再染。<br>颜色很正，掉色也慢，性价比比想象中好。<br>用了他们家的护发精油，效果很柔顺。<br>价格虽然不便宜，但品质对得起价格。<br>地址：水晶城3层<br>人均：180元<br>推荐指数：4.7星', 30, 5, '2022-02-10 14:00:00', NOW());
INSERT INTO `tb_blog` VALUES (26, 17, 1, '御足坊按摩100分钟，消除一周疲劳', '/imgs/blogs/blog1.jpg', '御足坊是朋友推荐的老店，周末去体验了100分钟足疗。<br>技师手法很专业，从泡脚到足底反射区全覆盖。<br>环境干净，淡淡的檀香味很放松。<br>按完整个人轻松很多，睡眠都变好了。<br>办卡的话性价比更高，下次打算试试全身推拿。<br>地址：金华路100号<br>人均：128元<br>推荐指数：4.6星', 22, 4, '2022-02-12 20:00:00', NOW());
INSERT INTO `tb_blog` VALUES (27, 20, 5, '超级猩猩团课初体验！燃脂效果拉满', '/imgs/blogs/blog1.jpg', '第一次上超级猩猩的杠铃操课，满头大汗太爽了！<br>教练很有感染力，会照顾到每个学员的动作。<br>小班教学，不超过15人，互动性很强。<br>健身房设施新，淋浴间干净，有吹风机。<br>月卡199元不限次，性价比在同类里算高的。<br>地址：运河上街F4<br>人均：199元/月<br>推荐指数：4.8星', 35, 6, '2022-02-14 09:00:00', NOW());
INSERT INTO `tb_blog` VALUES (28, 30, 2, 'Clarins SPA初体验！皮肤发光了', '/imgs/blogs/blog1.jpg', '花了588元体验了Clarins的90分钟面部护理。<br>用的全是Clarins本品牌产品，肤感很好。<br>美容师手法轻柔，还会介绍每个步骤的功效。<br>做完皮肤明显亮了一个度，补水效果肉眼可见。<br>虽然不便宜，但效果对得起价格，适合重要约会前来做。<br>地址：远洋乐堤港F3<br>人均：588元<br>推荐指数：4.9星', 45, 8, '2022-02-15 15:00:00', NOW());
INSERT INTO `tb_blog` VALUES (29, 35, 1, '带娃去了趟淘气堡，自己解放双手！', '/imgs/blogs/blog1.jpg', '周末带3岁宝宝去了淘气堡，大人小孩都开心！<br>设施很新，海洋球、滑梯、蹦床都有。<br>有专人看管，家长可以放心休息。<br>空间大，空气流通好，不像有些游乐场闷闷的。<br>68元一大一小，周末遛娃首选！<br>地址：运河上街F5<br>人均：68元<br>推荐指数：4.5星', 28, 3, '2022-02-16 11:00:00', NOW());
INSERT INTO `tb_blog` VALUES (30, 40, 5, 'THE VAULT酒吧，环境氛围满分', '/imgs/blogs/blog1.jpg', 'THE VAULT是拱墅区氛围感最好的酒吧之一。<br>装修风格很复古，灯光昏暗适合聊天。<br>点了两杯特调，口感均衡，酒精度数适中。<br>驻唱歌手唱功不错，周末有DJ打碟。<br>人均200左右，适合情侣约会或者朋友小聚。<br>地址：运河上街台州路8号<br>人均：220元<br>推荐指数：4.6星', 32, 5, '2022-02-18 22:00:00', NOW());
INSERT INTO `tb_blog` VALUES (31, 45, 1, '公司团建去了轰趴馆，玩到不想走', '/imgs/blogs/blog1.jpg', '部门12人团建选了轰趴猫，提前预约了下午场。<br>KTV、麻将、桌游、Switch全都有！<br>场地可以自己带食物饮料，非常适合团建。<br>老板很热情，会提前帮忙布置。<br>人均50不到，性价比超高，下次还来！<br>地址：运河上街台州路15号3楼<br>人均：45元<br>推荐指数：4.7星', 55, 9, '2022-02-20 14:00:00', NOW());
INSERT INTO `tb_blog` VALUES (32, 50, 2, 'NAIL PALACE做的渐变美甲，被问爆了', '/imgs/blogs/blog1.jpg', '在NAIL PALACE做了个日落渐变美甲，朋友圈炸了！<br>美甲师手艺很细，渐变过渡很自然。<br>用的都是环保甲油胶，没有刺鼻味道。<br>价格168元包卸甲，性价比在商圈里算实惠的。<br>提前预约不用等，推荐找Lisa做！<br>地址：运河上街B1<br>人均：168元<br>推荐指数：4.8星', 62, 12, '2022-02-22 16:00:00', NOW());
INSERT INTO `tb_blog` VALUES (33, 51, 2, '日系睫毛嫁接，自然到亲妈都看不出来', '/imgs/blogs/blog1.jpg', '在指尖花园做了日式蚕丝蛋白睫毛。<br>接出来很自然，一点都不夸张，眼睛有神多了。<br>美睫师很仔细，嫁接过程没有不适感。<br>可以维持一个月左右，性价比很高。<br>以后不用早起贴假睫毛了！<br>地址：远洋乐堤港F1<br>人均：198元<br>推荐指数：4.7星', 41, 7, '2022-02-25 11:00:00', NOW());
INSERT INTO `tb_blog` VALUES (34, 55, 1, '外婆家排队2小时值不值？值！', '/imgs/blogs/blog1.jpg', '周末6点到的外婆家，排队等了2小时才吃上。<br>等了这么久值得吗？我觉得值！<br>推荐几个必点：茶香鸡外酥里嫩；糖醋里脊酸甜刚好；酸菜鱼便宜大碗！<br>外婆家确实把杭帮菜做到了极致，性价比无敌。<br>建议提前网上取号，到店直接入座。<br>地址：运河上街F4<br>人均：50元<br>推荐指数：4.6星', 38, 6, '2022-02-26 18:30:00', NOW());
INSERT INTO `tb_blog` VALUES (35, 58, 1, '喜茶多肉葡萄真绝了，每周必喝', '/imgs/blogs/blog1.jpg', '喜茶的多肉葡萄真的太好喝了！<br>用的是新鲜葡萄，果肉满满，每一口都能吸到果肉。<br>芝士奶盖香浓不腻，甜度刚刚好。<br>远洋乐堤港这家店环境很好，有座位可以坐。<br>人均38元，虽然不便宜但值得！<br>地址：远洋乐堤港F1<br>人均：38元<br>推荐指数：4.8星', 88, 15, '2022-03-01 14:00:00', NOW());
INSERT INTO `tb_blog` VALUES (36, 2, 5, '蔡馬洪涛烤肉，铜锅涮肉太地道了', '/imgs/blogs/blog1.jpg', '这家老北京铜锅涮肉太正宗了！<br>炭火铜锅，手切羊肉，麻酱小料一绝。<br>羊蝎子也特别入味，越啃越香。<br>晚上营业到凌晨3点，宵夜首选！<br>就是位置有点偏，在上塘路老街上。<br>地址：上塘路1035号<br>人均：85元<br>推荐指数：4.7星', 29, 4, '2022-03-03 21:00:00', NOW());
INSERT INTO `tb_blog` VALUES (37, 3, 1, '新白鹿餐厅，实惠到不敢相信', '/imgs/blogs/blog1.jpg', '新白鹿是杭州学生党的食堂，人均50能吃撑！<br>蛋黄鸡翅外酥里嫩，强烈推荐！<br>东坡肉入口即化，配米饭绝了。<br>每道菜都在20-30元区间，实惠到不敢相信。<br>饭点必排队，建议错峰来。<br>地址：运河上街F5<br>人均：61元<br>推荐指数：4.5星', 33, 5, '2022-03-05 12:00:00', NOW());
INSERT INTO `tb_blog` VALUES (38, 4, 2, 'Mamala西餐，约会首选餐厅', '/imgs/blogs/blog1.jpg', 'Mamala是杭州高端西餐的代表，约会绝佳！<br>战斧牛排超大一份，五分熟刚刚好。<br>意面奶香浓郁，甜品提拉米苏入口即化。<br>环境有格调，灯光很适合拍照。<br>人均290元，适合纪念日来。<br>地址：远洋乐堤港2期1层<br>人均：290元<br>推荐指数：4.9星', 67, 11, '2022-03-08 19:00:00', NOW());
INSERT INTO `tb_blog` VALUES (39, 11, 1, 'INLOVE KTV：音响效果封神！', '/imgs/blogs/blog1.jpg', 'INLOVE的音响效果在杭州KTV里算顶尖的。<br>曲库非常全，新歌第一时间更新。<br>买了5小时套餐，人均才75元包含小食。<br>周末人很多，建议提前预约包厢。<br>有会员日活动，折扣很划算。<br>地址：水晶城6层<br>人均：75元<br>推荐指数：4.7星', 24, 3, '2022-03-10 20:00:00', NOW());
INSERT INTO `tb_blog` VALUES (40, 59, 5, '太二酸菜鱼，又酸又辣超级过瘾', '/imgs/blogs/blog1.jpg', '太二的酸菜鱼真是绝了！<br>鱼片薄如蝉翼，入口即化，酸辣度刚刚好。<br>米饭无限续，小菜也不错。<br>就是酸菜鱼有点辣，不太能吃辣的慎点。<br>人均78元，性价比很高。<br>地址：万达广场F4<br>人均：78元<br>推荐指数：4.6星', 21, 2, '2022-03-12 12:30:00', NOW());
INSERT INTO `tb_blog_comments` VALUES (1, 2, 4, 0, 0, '这家店确实很浪漫，适合拍照打卡！', 5, 0, '2022-03-10 20:00:00', NOW());
